import type { ReactElement, ReactNode } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import {
  createRootRoute,
  createRoute,
  createRouter,
} from "@tanstack/react-router";
import {
  render as baseRender,
  setupTestUtils,
  TestWrapper,
} from "@workspace/test-utils";

// Create a minimal test route tree
const rootRoute = createRootRoute();

const testRoute = createRoute({
  component: () => null,
  getParentRoute: () => rootRoute,
  path: "/",
});

const testRouteTree = rootRoute.addChildren([testRoute]);

// Create a test router
export const router = createRouter({
  defaultPreload: "intent",
  routeTree: testRouteTree,
});

// Create a test query client
export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      gcTime: 0,
      retry: false,
    },
  },
});

// Define our providers
const providers = [
  ({ children }: { children: ReactNode }) => (
    <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  ),
];

// Setup test utilities with our providers
export const { server } = setupTestUtils({
  // Add any additional setup here
  afterAll: async () => {
    // Any additional cleanup after all tests
  },
  afterEach: () => {
    // Any additional cleanup after each test
    queryClient.clear();
  },
  beforeAll: async () => {
    // Any additional setup before all tests
  },
  // Add any MSW handlers here
  handlers: [],
  providers,
});

export function render(ui: ReactElement, options = {}) {
  return baseRender(ui, {
    wrapper: ({ children }) => (
      <TestWrapper providers={providers}>{children}</TestWrapper>
    ),
    ...options,
  });
}

